class Solution:
    def smallestRangeI(self, nums, k):
        return max(0, (max(nums) - min(nums)) - 2 * k)

solutions.javascript:
var smallestRangeI = function(nums, k) {
    let mn = nums[0], mx = nums[0];
    for (const v of nums) {
        if (v < mn) mn = v;
        if (v > mx) mx = v;
    }
    return Math.max(0, (mx - mn) - 2 * k);
};
